import { Component } from '@angular/core';
import { ChatService } from '../services/chat.service';
import { TopicDialogComponent } from '../topic-dialog/topic-dialog.component';
import { MatDialog } from '@angular/material/dialog';

@Component({
  selector: 'app-chat',
  templateUrl: './chat.component.html',
  styleUrls: ['./chat.component.scss']
})
export class ChatComponent {

  messages: string[] = [];
  userMessage: string = '';


  constructor(private chatService: ChatService, private dialog: MatDialog) { }

  input_text: string = '';

  prompt: string = '';
  istyping: boolean = false;
  isPlaying: boolean = false;


  topics = [
    { title: 'Тема 1', description: 'Описание темы 1', fullResponse: 'Полный ответ для темы 1' },
    { title: 'Тема 2', description: 'Описание темы 2', fullResponse: 'Полный ответ для темы 2' }
  ];


  sendMessage() {
    if (!this.input_text.trim() || this.isPlaying) {
      this.input_text = '';
      console.log(1);
      return;
    }

    this.topics.push({
      title: this.input_text,
      description: 'Описание для ' + this.input_text,
      fullResponse: 'Полный ответ для темы 1'
    });

    console.log(2);
    this.input_text = '';
  }

  // openDialog(fullResponse: string) {
  //   alert(fullResponse);
  // }

  openDialog(title: string, fullResponse: string) {
    this.dialog.open(TopicDialogComponent, {
        data: { title, fullResponse }
    });
}


}
